import * as http from "http";
import * as net from "net";
import { spawn, type ChildProcessWithoutNullStreams } from "child_process";

/**
 * A local HTTP/SSE proxy that makes the MiMo CLI look like an OpenCode server
 * to the OpenCode GUI webview (which talks to `@opencode-ai/sdk` over REST+SSE).
 *
 * MiMo compatibility (verified against mimo run --format json):
 *   - `mimo serve` already exposes GET /session, POST /session,
 *     GET /session/:id/message, GET /agent, GET /mcp, GET /config (same paths
 *     the SDK expects), so those are proxied straight through.
 *   - Chat is NOT a REST endpoint on mimo; it streams via
 *     `mimo run --format json --attach <serve> --session <id> "<prompt>"`.
 *     The JSON events (step_start / text / step_finish with part{type,text,
 *     messageID}) match OpenCode SDK SSE shapes, so we wrap each NDJSON line
 *     as an SSE `data:` frame on POST /session/:id/message.
 */

interface MimoProxyOptions {
  mimoBin: string;
  serveUrl: string; // http://127.0.0.1:<port> of `mimo serve`
  hostname?: string;
  port?: number; // 0 = ephemeral
}

export class MimoProxy {
  private server?: http.Server;
  private _url = "";
  private activeRuns = new Map<string, ChildProcessWithoutNullStreams>();

  constructor(private readonly opts: MimoProxyOptions) {}

  get url() {
    return this._url;
  }

  async start(): Promise<string> {
    const host = this.opts.hostname ?? "127.0.0.1";
    const port = this.opts.port ?? 0;

    this.server = http.createServer((req, res) => {
      this.handle(req, res).catch((err) => {
        if (!res.headersSent) {
          res.writeHead(500, { "content-type": "text/plain" });
          res.end(String(err));
        }
      });
    });

    await new Promise<void>((resolve, reject) => {
      this.server!.on("error", reject);
      this.server!.listen(port, host, () => resolve());
    });

    const addr = this.server.address() as net.AddressInfo;
    this._url = `http://${host}:${addr.port}`;
    return this._url;
  }

  stop() {
    for (const proc of this.activeRuns.values()) proc.kill();
    this.activeRuns.clear();
    this.server?.close();
  }

  private async handle(req: http.IncomingMessage, res: http.ServerResponse) {
    const url = new URL(req.url ?? "/", this._url);
    const path = url.pathname;
    const method = (req.method ?? "GET").toUpperCase();

    // ---- SSE event channel (global live updates) ----
    if (path === "/event" || path === "/global/event") {
      this.handleEventStream(res);
      return;
    }

    // ---- Chat: POST /session/:id/message -> spawn mimo run, stream as SSE ----
    const promptMatch = path.match(/^\/session\/([^/]+)\/message$/);
    if (method === "POST" && promptMatch) {
      const sessionId = decodeURIComponent(promptMatch[1]);
      await this.handlePrompt(sessionId, req, res);
      return;
    }

    // ---- Everything else: proxy to mimo serve ----
    await this.proxyToServe(req, res, url, method);
  }

  /** Global SSE channel. MiMo has no equivalent push channel, so we keep the
   *  connection open and emit a heartbeat; the webview tolerates no events. */
  private handleEventStream(res: http.ServerResponse) {
    res.writeHead(200, {
      "content-type": "text/event-stream",
      "cache-control": "no-cache",
      connection: "keep-alive",
      "access-control-allow-origin": "*",
    });
    res.write("retry: 3000\n\n");
    const heartbeat = setInterval(() => res.write(": ping\n\n"), 15000);
    const onClose = () => clearInterval(heartbeat);
    res.on("close", onClose);
    res.on("error", onClose);
  }

  private async handlePrompt(
    sessionId: string,
    req: http.IncomingMessage,
    res: http.ServerResponse,
  ) {
    const body = await readBody(req);
    let payload: any = {};
    try {
      payload = body ? JSON.parse(body) : {};
    } catch {
      /* ignore */
    }

    // Build the prompt text from the SDK `parts` shape.
    const parts: any[] = payload.parts ?? [];
    const textParts = parts
      .filter((p) => p && (p.type === "text" || p.text != null))
      .map((p) => (typeof p === "string" ? p : p.text))
      .join("\n");
    const model: string | undefined = payload.model;
    const agent: string | undefined = payload.agent;
    const prompt = textParts || (payload.text ?? "");

    // Use --port (attach to the running serve). The prompt must be the FIRST
    // positional arg (right after `run`) — mimo ignores a trailing positional
    // and drops into an interactive REPL that never closes the SSE stream.
    const servePort = new URL(this.opts.serveUrl).port;
    const args: string[] = ["run", prompt, "--format", "json", "--port", servePort];
    if (sessionId) {
      args.push("--continue", "--session", sessionId);
    }
    if (model) args.push("--model", model);
    if (agent) args.push("--agent", agent);

    let child: ChildProcessWithoutNullStreams;
    try {
      child = spawn(this.opts.mimoBin, args, {
        windowsHide: true,
        // Ignore stdin so mimo run does not block waiting for interactive
        // input; pipe stdout/stderr so we can wrap JSON events as SSE.
        stdio: ["ignore", "pipe", "pipe"],
        env: { ...process.env },
      });
    } catch (err) {
      res.writeHead(500, { "content-type": "text/plain" });
      res.end(String(err));
      return;
    }

    this.activeRuns.set(sessionId, child);

    res.writeHead(200, {
      "content-type": "text/event-stream",
      "cache-control": "no-cache",
      connection: "keep-alive",
      "access-control-allow-origin": "*",
    });
    res.write("retry: 3000\n\n");

    let buf = "";
    const flushLine = (line: string) => {
      const t = line.trim();
      if (!t) return;
      // mimo emits one JSON event per line; wrap as SSE data frame.
      res.write(`data: ${t}\n\n`);
    };

    child.stdout.on("data", (chunk: Buffer) => {
      buf += chunk.toString();
      let idx: number;
      while ((idx = buf.indexOf("\n")) >= 0) {
        const line = buf.slice(0, idx);
        buf = buf.slice(idx + 1);
        flushLine(line);
      }
    });
    child.stderr.on("data", (chunk: Buffer) => {
      // Surface mimo errors as an SSE error frame.
      res.write(`event: error\ndata: ${JSON.stringify({ error: chunk.toString() })}\n\n`);
    });
    child.on("close", () => {
      if (buf.trim()) flushLine(buf);
      this.activeRuns.delete(sessionId);
      res.write("event: done\ndata: {}\n\n");
      res.end();
    });
    child.on("error", (err) => {
      res.write(`event: error\ndata: ${JSON.stringify({ error: String(err) })}\n\n`);
      res.end();
    });

    req.on("close", () => {
      child.kill();
      this.activeRuns.delete(sessionId);
    });
  }

  private async proxyToServe(
    req: http.IncomingMessage,
    res: http.ServerResponse,
    url: URL,
    method: string,
  ) {
    const target = `${this.opts.serveUrl}${url.pathname}${url.search}`;
    const body = method === "GET" || method === "HEAD" ? undefined : await readBody(req);

    const proxyReq = http.request(
      target,
      {
        method,
        headers: {
          "content-type": "application/json",
          ...stripHopByHop(req.headers),
        },
      },
      (proxyRes) => {
        res.writeHead(proxyRes.statusCode ?? 502, stripHopByHop(proxyRes.headers));
        proxyRes.pipe(res);
      },
    );
    proxyReq.on("error", (err) => {
      if (!res.headersSent) {
        res.writeHead(502, { "content-type": "text/plain" });
        res.end(String(err));
      }
    });
    if (body) proxyReq.write(body);
    proxyReq.end();
  }
}

function readBody(req: http.IncomingMessage): Promise<string> {
  return new Promise((resolve) => {
    let data = "";
    req.on("data", (c) => (data += c));
    req.on("end", () => resolve(data));
    req.on("error", () => resolve(data));
  });
}

function stripHopByHop(headers: http.IncomingHttpHeaders): Record<string, string> {
  const out: Record<string, string> = {};
  const skip = new Set(["host", "connection", "content-length", "transfer-encoding"]);
  for (const [k, v] of Object.entries(headers)) {
    if (skip.has(k.toLowerCase())) continue;
    if (Array.isArray(v)) out[k] = v.join(", ");
    else if (v != null) out[k] = String(v);
  }
  return out;
}
